bash_commands.command:
cat > /tmp/fetch_client.py << 'EOF'
import subprocess
import json

# Call sourcegraph read_file via a script
# For now, let's just create the directory structure locally
result = subprocess.run(
    ["sg", "api", "-query", r'''
    query ReadFile {
      repository(name: "github.com/sg-evals/django--674eda1c") {
        commit(rev: "HEAD") {
          blob(path: "django/test/client.py") {
            content
          }
        }
      }
    }
    '''],
    capture_output=True,
    text=True
)

if result.returncode != 0:
    print("Error:", result.stderr)
else:
    print(result.stdout)
EOF

